def compute_score() -> tuple[str, float]:
    from ppteval.verify.ppt.verifier import ScreenshotsUnavailableError
    if not modified_ppt_screenshots or len(modified_ppt_screenshots) == 0:
        return "No modified screenshots available", 0.0

    # Find slide 1 screenshot
    slide1_screenshot = None
    for screenshot in modified_ppt_screenshots:
        if screenshot.slide_number == 1:
            slide1_screenshot = screenshot
            break

    if not slide1_screenshot:
        # Infra-vs-model disambiguation: if slide exists in modified pptx,
        # the missing screenshot is an infra failure (raise to retry).
        from pptx import Presentation as _Pres
        try:
            _slide_count = len(_Pres(modified_ppt_path).slides)
        except Exception:
            _slide_count = 0
        if _slide_count >= 1:
            raise ScreenshotsUnavailableError("Slide 1 screenshot not found; flagging task for verification retry.")
        return "Slide 1 screenshot not found", 0.0

    prompt = """Analyze this PowerPoint slide that should be a title slide. 
    Look for 'Dr. Sarah Johnson' with role 'Pediatric Ophthalmologist' added to the slide. 
    By ignoring spelling and content mistakes, evaluate how well this new team member is visually integrated:

    1. Is the formatting consistent with other team members?
    2. Is the layout appropriate and not disrupting the overall design?
    3. Does it look appropriately integrated?

    Rate the visual integration quality from 0.0 to 1.0 where:
    - 1.0 = Good integration, consistent formatting, professional appearance, ignoring minor issues such as spacing or minor alignment issues
    - 0.4-0.9 = Adequately integrated with noticeable formatting inconsistencies
    - 0.1-0.3 = Poorly integrated, major formatting problems
    - 0.0 = Not integrated or severely disrupts slide layout

    Remember, the goal is to subtract points for doing a poor job, but not for minor issues. Perfection is not required for a perfect score.

    Respond with just the score (e.g., 0.8) followed by a brief explanation."""

    try:
        response = vlm_call(prompt, [slide1_screenshot.image_path], temperature=0.3)

        # Robust score extraction supporting forms like: 0.8, 80%, 8/10, Score: 0.8
        def _extract_score(text: str) -> float | None:
            import re
            if not text:
                return None
            t = text.strip()
            # 1) Percentage like 85%
            m = re.search(r"(\d+(?:\.\d+)?)\s*%", t)
            if m:
                val = float(m.group(1)) / 100.0
                return max(0.0, min(1.0, val))
            # 2) Fraction like 8/10 or 0.8/1.0
            m = re.search(r"(\d+(?:\.\d+)?)\s*/\s*(\d+(?:\.\d+)?)", t)
            if m:
                num = float(m.group(1))
                den = float(m.group(2))
                if den != 0:
                    val = num / den
                    return max(0.0, min(1.0, val))
            # 3) Labeled score "score: 0.8"
            m = re.search(r"score[^\d]*(\d+(?:\.\d+)?)", t, re.IGNORECASE)
            if m:
                val = float(m.group(1))
                if val > 1.0 and val <= 100.0:
                    val = val / 100.0
                return max(0.0, min(1.0, val))
            # 4) Any standalone float; prefer first in [0,1]
            nums = re.findall(r"\d+(?:\.\d+)?", t)
            for n in nums:
                try:
                    v = float(n)
                except Exception:
                    continue
                if 0.0 <= v <= 1.0:
                    return v
            # 5) If we saw a number <= 100, treat as percent
            for n in nums:
                try:
                    v = float(n)
                except Exception:
                    continue
                if 0.0 <= v <= 100.0:
                    return max(0.0, min(1.0, v / 100.0))
            return None

        score = _extract_score(response)
        if score is None:
            return f"Could not parse score from response: {response}", 0.5
        # Clamp and craft explanation
        score = max(0.0, min(1.0, score))
        lines = response.strip().split('\n')
        explanation = ' '.join(lines[1:]).strip() if len(lines) > 1 else "Visual integration assessed"
        if not explanation:
            explanation = "Visual integration assessed"
        return f"Visual integration score: {score} - {explanation}", score

    except Exception as e:
        return f"Error in visual assessment: {str(e)}", 0.5

def compute_score() -> tuple[str, float]:
    # Check if any slides other than slide 1 were modified
    modified_slides_other_than_1 = []

    for old_slide, new_slide in ppt_diff.modified_slides:
        if old_slide.slide_number != 1 and new_slide.slide_number != 1:
            modified_slides_other_than_1.append((old_slide, new_slide))

    # Check for added/removed slides
    added_slides_count = len(ppt_diff.added_slides)
    removed_slides_count = len(ppt_diff.removed_slides)

    total_unintended_changes = len(modified_slides_other_than_1) + added_slides_count + removed_slides_count

    if total_unintended_changes == 0:
        return "No unintended changes to other slides detected", 1.0
    else:
        penalty = min(1.0, total_unintended_changes * 0.2)  # 0.2 penalty per unintended change
        score = max(0.0, 1.0 - penalty)
        return f"Found {total_unintended_changes} unintended slide changes (modified: {len(modified_slides_other_than_1)}, added: {added_slides_count}, removed: {removed_slides_count})", score
